<?= $this->extend('layouts/panel') ?><?= $this->section('content') ?><?php $errors=session('errors')??[];$statusLabels=['pending'=>'Bekleyen','earned'=>'Hak edildi','paid'=>'Ödendi','reversed'=>'Ters kayıt'];$entryTotals=$entries;[$entries,$pagination]=\App\Libraries\TablePaginator::paginateArray($entries,\App\Libraries\TablePaginator::state(service('request'),'commissions')); ?><div class="page-actions"><div><p class="page-lead">Siparişlerden oluşan primleri ve dönem durumlarını izleyin.</p></div><?php if($canManage): ?><form method="post" action="<?= site_url('panel/primler/hesapla') ?>"><?= csrf_field() ?><button class="button" type="submit">Primleri hesapla</button></form><?php endif; ?></div><?php if($errors): ?><div class="alert alert--error"><?= esc(reset($errors)) ?></div><?php endif; ?><div class="stats-grid"><?php foreach(['pending'=>'Bekleyen','earned'=>'Hak edilmiş','paid'=>'Ödenen'] as $key=>$label):$total=array_sum(array_map(fn($e)=>$e['status']===$key?(float)$e['commission_amount']:0,$entryTotals)); ?><article class="stat-card"><span><?= $label ?></span><strong><?= number_format($total,2,',','.') ?> ₺</strong></article><?php endforeach; ?></div>
