<section class="panel-card"><div class="table-wrap"><table class="data-table"><thead><tr><th>ID</th><th>Personel</th><th>Sipariş</th><th>Kural</th><th>Matrah</th><th>Oran</th><th>Prim</th><th>Durum</th></tr></thead><tbody><?php foreach($entries as $e): ?><tr><td data-label="ID"><strong>#<?= (int) $e['id'] ?></strong></td><td data-label="Personel"><?= esc($e['full_name']) ?></td><td data-label="Sipariş"><?= esc($e['document_number']) ?></td><td data-label="Kural"><?= esc($e['rule_name']) ?></td><td data-label="Matrah"><?= number_format((float)$e['base_amount'],2,',','.') ?> ₺</td><td data-label="Oran">%<?= number_format((float)$e['rate_percent'],2,',','.') ?></td><td data-label="Prim"><strong><?= number_format((float)$e['commission_amount'],2,',','.') ?> ₺</strong></td><td data-label="Durum"><span class="badge <?= $e['status']==='paid'?'badge--success':'badge--warning' ?>"><?= esc($statusLabels[$e['status']]??$e['status']) ?></span></td></tr><?php endforeach; ?></tbody></table></div><?= view('components/table_pagination', ['pagination' => $pagination]) ?></section><?php if($canManage&&$periods): ?><section class="panel-card"><div class="table-wrap"><table class="data-table"><thead><tr><th>ID</th><th>Dönem</th><th>Tarih</th><th>Durum</th><th></th></tr></thead><tbody><?php foreach($periods as $p): ?><tr><td data-label="ID"><strong>#<?= (int) $p['id'] ?></strong></td><td data-label="Dönem"><?= esc($p['period_code']) ?></td><td data-label="Tarih"><?= esc($p['starts_on'].' — '.$p['ends_on']) ?></td><td data-label="Durum"><?= esc($p['status']) ?></td><td data-label="İşlem"><?php if($p['status']==='closed'): ?><form method="post" action="<?= site_url('panel/primler/donem/'.$p['id'].'/ode') ?>"><?= csrf_field() ?><button class="button button--secondary" type="submit">Ödendi işaretle</button></form><?php endif; ?></td></tr><?php endforeach; ?></tbody></table></div></section><?php endif; ?><?= $this->endSection() ?>
